import{_ as t,c as r,o as n,ae as s}from"./chunks/framework.B7Y1jjX-.js";const u=JSON.parse('{"title":"研究目的与数据对象","description":"","frontmatter":{},"headers":[],"relativePath":"notes/学习/学校竞赛、项目/数学建模/课程知识/第一题框架.md","filePath":"notes/学习/学校竞赛、项目/数学建模/课程知识/第一题框架.md"}'),g={name:"notes/学习/学校竞赛、项目/数学建模/课程知识/第一题框架.md"};function l(a,o,i,e,m,p){return n(),r("div",null,[...o[0]||(o[0]=[s('<p>下面把你这份“<strong>第一题：变量分布→相关性→Gamma 回归</strong>”脚本改写成论文/报告可用的<strong>方法描述</strong>，并逐段解释“<strong>为什么要这么做</strong>”。</p><hr><h1 id="研究目的与数据对象" tabindex="-1">研究目的与数据对象 <a class="header-anchor" href="#研究目的与数据对象" aria-label="Permalink to &quot;研究目的与数据对象&quot;">​</a></h1><p><strong>目标</strong>：刻画男胎样本中 <strong>Y 染色体浓度</strong>（下称 <em>Y 浓度</em>）与若干候选影响因子（孕周、BMI、年龄、染色体 Z 值、测序质量指标等）的关系，完成从<strong>分布检验 → 相关结构 → 回归建模</strong>的分析闭环，输出可解释的统计证据与可视化结果。</p><p><strong>对象与预处理</strong></p><ul><li>从原始表格读取男胎数据（以“Y 染色体浓度”非空作为男胎判据），并将“检测孕周”统一解析为<strong>浮点周</strong>（支持 <code>16w+2 / 16+2 / 16周+2天 / 16.5</code> 等格式），仅保留 <strong>[10, 25] 周</strong>合法时窗内记录。</li><li>指定候选变量集合：母体特征（年龄、BMI）、检测孕周、染色体相关指标（X/Y/13/18/21 的 Z 值与 GC 含量）、测序质量（读段数、比对率、重复率、唯一比对读段、过滤比例等）。</li></ul><p><strong>为什么</strong>：</p><ul><li>统一孕周刻度是时间相关分析的前提；限定 10–25 周避免窗口外的分布偏移。</li><li>候选变量覆盖母体因素、遗传信号与测序质量三类信息，基本囊括对 <em>Y 浓度</em> 可能的主导与混杂来源。</li></ul><hr><h1 id="步骤一-变量分布与正态性检验" tabindex="-1">步骤一：变量分布与<strong>正态性检验</strong> <a class="header-anchor" href="#步骤一-变量分布与正态性检验" aria-label="Permalink to &quot;步骤一：变量分布与**正态性检验**&quot;">​</a></h1><p><strong>做法</strong></p><ul><li>对每个变量执行 <strong>Shapiro–Wilk 正态性检验</strong>（报告统计量 W 与 p 值）。</li><li>同时绘制**直方图 + 核密度曲线（KDE）**与 <strong>Q–Q 图</strong>，并给出均值、标准差、偏度与峰度等描述性统计；在图中对“是否近似正态”进行视觉与数理双重判断。</li></ul><p><strong>为什么先做正态检验</strong>：</p><ol><li><strong>选择合适的相关性度量与建模族</strong>：如果变量/残差明显偏离正态，直接使用皮尔逊相关或 OLS 线性回归的前提将受损。先检验分布，有助于后续决定采用<strong>皮尔逊 vs 斯皮尔曼</strong>相关、是否做<strong>变换/稳健回归</strong>，或直接转向**广义线性模型（GLM）**族。</li><li><strong>识别重尾/偏态与异常值</strong>：偏度、峰度与 Q–Q 图能提示<strong>右偏/长尾</strong>与极端点，指导后续是否需要<strong>对数变换</strong>或更换误差分布。</li><li><strong>保障可解释性</strong>：直方图/KDE 与 Q–Q 图把“统计检验结果”转化为可视证据，便于和临床/实验团队沟通。</li></ol><hr><h1 id="步骤二-相关结构——相关系数矩阵与热力图" tabindex="-1">步骤二：相关结构——<strong>相关系数矩阵与热力图</strong> <a class="header-anchor" href="#步骤二-相关结构——相关系数矩阵与热力图" aria-label="Permalink to &quot;步骤二：相关结构——**相关系数矩阵与热力图**&quot;">​</a></h1><p><strong>做法</strong></p><ul><li>基于清洗后的数据计算变量间的相关系数矩阵，并绘制<strong>热力图</strong>（带数值标注）。</li><li>重点关注各变量与 <em>Y 浓度</em> 的相关程度，以初步筛查<strong>线性相关</strong>或<strong>强共线</strong>（例如 GC、比对率、读段等质量指标之间）。</li></ul><p><strong>为什么把热力图放在正态检验之后</strong>：</p><ul><li><p>相关系数（默认皮尔逊）本质上度量<strong>线性关系</strong>且受分布与异常值影响较大。先做分布与异常识别，能帮助：</p><ul><li>判断“<strong>皮尔逊是否合适</strong>”，或是否需要补做<strong>斯皮尔曼（秩相关）<strong>以刻画</strong>单调但非线性</strong>的关联；</li><li>结合分布形态解释“为什么同样的相关数值在不同变量上可靠性不同”（如一侧重尾导致的虚高/虚低）。</li></ul></li><li><p>热力图是<strong>变量缩减与多重共线</strong>预警的入口，为后续回归的变量选择与解释做准备。</p></li></ul><hr><h1 id="步骤三-gamma-回归-glm-log-链接-建模-y-浓度" tabindex="-1">步骤三：**Gamma 回归（GLM，log 链接）**建模 <em>Y 浓度</em> <a class="header-anchor" href="#步骤三-gamma-回归-glm-log-链接-建模-y-浓度" aria-label="Permalink to &quot;步骤三：\\*\\*Gamma 回归（GLM，log 链接）\\*\\*建模 *Y 浓度*&quot;">​</a></h1><p><strong>做法</strong></p><ul><li><p>以 <em>Y 浓度</em> 为因变量（正且连续），分别用四个自变量（检测孕周、BMI、年龄、18 号染色体 Z 值）单变量地拟合 <strong>Gamma–Log GLM</strong>：</p><p>$$ \\mathbb{E}(Y\\mid X)=\\mu,\\quad \\log\\mu=\\beta_0+\\beta_1 X,\\quad Y\\sim\\text{Gamma}(\\mu,\\phi) $$</p></li><li><p>输出每个模型的<strong>系数、p 值、显著性</strong>与<strong>回归诊断摘要</strong>；绘制<strong>散点 + Gamma 回归曲线</strong>以展示拟合趋势。</p></li><li><p>进一步计算“自变量 vs 该模型预测值”的<strong>斯皮尔曼相关</strong>，验证回归给出的<strong>单调性</strong>与<strong>排序一致性</strong>。</p></li></ul><p><strong>为什么选 Gamma 回归而不是 OLS/Poisson/Lognormal 等</strong>：</p><ol><li><strong>数据类型匹配</strong>：<em>Y 浓度</em> 为<strong>正值、右偏、方差随均值增大</strong>的连续量。Gamma 分布的<strong>均值–方差关系（Var ∝ μ²）<strong>正好匹配这类</strong>异方差</strong>、<strong>比例型</strong>数据特征。</li><li><strong>非负与比例的自然约束</strong>：Gamma–log 保证 <strong>μ&gt;0</strong>，不产生负预测，且 log 链接提供<strong>乘法效应解释</strong>（自变量每增加 1 单位，期望值按 $e^{\\beta_1}$ 倍变化），对“比率/浓度”类对象更贴近<strong>生物学与测序过程</strong>。</li><li><strong>比“log 变换 + OLS”更规范</strong>：对数变换后做 OLS 在<strong>误差分布/回到原尺度的偏差修正</strong>上往往不严谨；GLM 直接在原尺度下以合适的<strong>似然</strong>与<strong>连接函数</strong>建模，更易获得<strong>一致的估计与稳健的推断</strong>。</li><li><strong>相对 Poisson/负二项</strong>：它们用于<strong>计数</strong>或<strong>离散非负整数</strong>，不适合连续浓度。</li><li><strong>相对 Beta 回归</strong>：Beta 适合**(0,1)** 区间内的比例且靠近 0/1 时需特殊处理；本数据虽可视作比例，但更贴近<strong>正的连续测量</strong>且可能存在少量等于 0 的情形，Gamma–log 更稳妥。</li><li><strong>诊断与可解释性</strong>：Gamma–log 的残差与 Brier/标定曲线（若做概率化）等指标能更好地反映<strong>均值–方差耦合</strong>下的拟合优劣；曲线可视化直观展示<strong>非线性单调趋势</strong>。</li></ol><blockquote><p>小结：<strong>Gamma–log = 正值 + 右偏 + 随均值增大的方差 + 乘法效应解释</strong> —— 与 <em>Y 浓度</em> 的统计属性和机理假设高度吻合。</p></blockquote><hr><h1 id="结果解读与报告建议" tabindex="-1">结果解读与报告建议 <a class="header-anchor" href="#结果解读与报告建议" aria-label="Permalink to &quot;结果解读与报告建议&quot;">​</a></h1><ol><li><p><strong>分布层</strong>：给出每个变量的 W 与 p 值、偏度/峰度，以及直方图+KDE与 Q–Q 图的要点解读（例如“孕周近似单峰右偏，偏度&gt;0；Y 浓度显著右偏，Shapiro-Wilk p&lt;0.05，不服从正态”）。</p></li><li><p><strong>相关层</strong>：热力图中标注与 <em>Y 浓度</em> 相关性绝对值较高的变量，并指出<strong>质量指标间可能共线</strong>（为多元建模做准备）。必要时补充<strong>斯皮尔曼矩阵</strong>对比。</p></li><li><p><strong>回归层</strong>：逐个自变量的 Gamma–log 拟合结果（系数、标准误、p 值、显著性），配合“散点+拟合曲线”图解释<strong>方向与强度</strong>（如“孕周系数显著为正，呈加速增长趋势”“BMI 为轻度负相关且显著性边缘”等——以你实际跑出的结果为准）。</p></li><li><p><strong>稳健性与局限</strong>：</p><ul><li>若发现严重异方差或极端点，记录在分布与残差图中，并说明对估计的潜在影响；</li><li>指出本步骤系<strong>单变量</strong> GLM，后续可扩展为<strong>多变量</strong> Gamma–log 或<strong>分层/混合效应</strong>模型（如按批次/平台随机截距）以处理批间差异与潜在混杂。</li></ul></li></ol><hr><h1 id="流程一图流-便于写在方法概览" tabindex="-1">流程一图流（便于写在方法概览） <a class="header-anchor" href="#流程一图流-便于写在方法概览" aria-label="Permalink to &quot;流程一图流（便于写在方法概览）&quot;">​</a></h1><ol><li><strong>清洗与统一刻度</strong>（孕周解析为 10–25 的浮点周；筛掉缺失/异常）。</li><li><strong>正态性与分布可视化</strong>（Shapiro–Wilk + 直方图/KDE + Q–Q）。</li><li><strong>相关结构</strong>（相关矩阵 + 热力图；必要时补斯皮尔曼）。</li><li><strong>Gamma–log 回归</strong>（单变量，输出统计检验与拟合曲线）。</li><li><strong>相关性与预测一致性</strong>（自变量与模型预测值的斯皮尔曼相关，检验单调性）。</li></ol><hr><h3 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to &quot;一句话总结&quot;">​</a></h3><p>先用<strong>正态性检验</strong>确保我们选择<strong>合适的相关度量与模型族</strong>，再用<strong>热力图</strong>把相关结构与多重共线直观看清，最后以<strong>Gamma–log 回归</strong>建模一个<strong>正值、右偏、异方差</strong>的浓度型因变量，从统计假设与生物学机理两端同时保证<strong>合理性、稳健性与可解释性</strong>。</p>',36)])])}const d=t(g,[["render",l]]);export{u as __pageData,d as default};
